package com.chaobo.scm.supplier.application.score;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.shared.*;import com.chaobo.scm.supplier.infrastructure.persistence.score.SupplierScoreMapper;import tools.jackson.core.JacksonException;import tools.jackson.databind.ObjectMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.*;import java.time.*;import java.util.*;
@Service public class SupplierScoreApplicationService{private final SupplierScoreMapper mapper;private final IdentifierGenerator ids;private final ObjectMapper json;private final OutboxRepository outbox;private final AuditLogRepository audit;public SupplierScoreApplicationService(SupplierScoreMapper mapper,IdentifierGenerator ids,ObjectMapper json,OutboxRepository outbox,AuditLogRepository audit){this.mapper=mapper;this.ids=ids;this.json=json;this.outbox=outbox;this.audit=audit;}@Transactional public boolean collectFact(PerformanceFactEvent e){var metric=metric(e.eventType());if(e.supplierId()<=0||e.metricValue()==null||e.occurredAt()==null)throw rule("绩效事实数据不完整");return mapper.insertFact(ids.nextId(),e.eventCode(),e.supplierId(),metric.dimension(),metric.metric(),e.metricValue(),e.occurredAt(),e.sourceSystem(),e.sourceNo(),write(e.payload()==null?Map.of():e.payload()))==1;}@Transactional public long createRule(String name,String dimension,String metric,BigDecimal weight,BigDecimal target,int direction,LocalDate from,LocalDate to,CommandContext c){c.requirePermission("supplier:score-rule:create");if(name==null||name.isBlank()||dimension==null||dimension.isBlank()||metric==null||metric.isBlank()||weight==null||weight.signum()<=0||weight.compareTo(BigDecimal.ONE)>0||target==null||target.signum()<=0||direction<1||direction>2||from==null||(to!=null&&to.isBefore(from)))throw rule("评分规则不合法");long id=ids.nextId();mapper.insertRule(id,name,dimension,metric,weight,target,direction,from,to,c.operatorId());audit.save(c,"CREATE_SCORE_RULE","SCORE_RULE",id,name,null,"{\"status\":1}");return id;}@Transactional public void publishRule(long id,int version,CommandContext c){c.requirePermission("supplier:score-rule:publish");if(mapper.publishRule(id,version,c.operatorId())!=1)throw conflict();audit.save(c,"PUBLISH_SCORE_RULE","SCORE_RULE",id,String.valueOf(id),null,"{\"status\":2}");}@Transactional public void disableRule(long id,int version,CommandContext c){c.requirePermission("supplier:score-rule:disable");if(mapper.disableRule(id,version,c.operatorId())!=1)throw conflict();audit.save(c,"DISABLE_SCORE_RULE","SCORE_RULE",id,String.valueOf(id),null,"{\"status\":3}");}@Transactional(readOnly=true)public List<ScoreViews.Rule> rules(){return mapper.rules();}
 @Transactional public ScoreViews.Result calculate(long supplierId,YearMonth period,BigDecimal adjustment,String reason,CommandContext c){c.requirePermission("supplier:score:calculate");c.requireSupplierScope(supplierId);adjustment=adjustment==null?BigDecimal.ZERO:adjustment;if(adjustment.signum()!=0&&(reason==null||reason.isBlank()))throw rule("人工修正必须说明原因");OffsetDateTime from=period.atDay(1).atStartOfDay().atOffset(ZoneOffset.ofHours(8)),to=period.plusMonths(1).atDay(1).atStartOfDay().atOffset(ZoneOffset.ofHours(8));var ruleRows=mapper.effectiveRules(period.atEndOfMonth());var facts=mapper.facts(supplierId,from,to);var result=SupplierScoringDomainService.calculate(ruleRows.stream().map(r->new SupplierScoringDomainService.Rule(r.dimensionCode(),r.metricCode(),r.weight(),r.targetValue(),r.direction())).toList(),facts.stream().map(f->new SupplierScoringDomainService.Fact(f.metricCode(),f.metricValue())).toList(),adjustment);String periodCode=period.toString();mapper.upsertResult(ids.nextId(),supplierId,periodCode,result.total(),write(result.dimensions()),write(Map.of("factCount",facts.size(),"eventCodes",facts.stream().map(ScoreViews.Fact::eventCode).toList())),adjustment,reason);var saved=mapper.resultByPeriod(supplierId,periodCode);audit.save(c,"CALCULATE_SUPPLIER_SCORE","SCORE_RESULT",saved.id(),periodCode,null,"{\"totalScore\":"+saved.totalScore()+"}");return saved;}@Transactional public ScoreViews.Result publish(long id,int version,CommandContext c){c.requirePermission("supplier:score:publish");var row=mapper.result(id);if(row==null)throw new BusinessException(ErrorCode.NOT_FOUND,"评分结果不存在");c.requireSupplierScope(row.supplierId());if(mapper.publishResult(id,version)!=1)throw conflict();if(row.totalScore().compareTo(new BigDecimal("75"))<0){boolean high=row.totalScore().compareTo(new BigDecimal("60"))<0;mapper.insertRisk(ids.nextId(),row.supplierId(),id,high?3:2,high?3:1,"供应商周期评分"+row.totalScore()+"分，建议"+(high?"进行冻结审批":"发起整改"));}long eventId=ids.nextId();outbox.saveAll(List.of(new DomainEvent(eventId,"SUP-"+eventId,"SupplierScorePublished","供应商评分已发布","SUPPLIER_SCORE",id,row.periodCode(),version+1,c.operatorId(),OffsetDateTime.now(),Map.of("supplierId",row.supplierId(),"periodCode",row.periodCode(),"totalScore",row.totalScore()))));audit.save(c,"PUBLISH_SUPPLIER_SCORE","SCORE_RESULT",id,row.periodCode(),"{\"status\":1}","{\"status\":2}");return mapper.result(id);}@Transactional(readOnly=true)public ScoreViews.Result result(long supplierId,String period,Long scope){if(scope!=null&&scope!=supplierId)throw new BusinessException(ErrorCode.NOT_FOUND,"评分结果不存在");var r=mapper.resultByPeriod(supplierId,period);if(r==null)throw new BusinessException(ErrorCode.NOT_FOUND,"评分结果不存在");return r;}@Transactional(readOnly=true)public List<ScoreViews.Risk> risks(long supplierId,Long scope){if(scope!=null&&scope!=supplierId)throw new BusinessException(ErrorCode.NOT_FOUND,"风险建议不存在");return mapper.risks(supplierId);}@Transactional public void processRisk(long id,int version,boolean accepted,CommandContext c){c.requirePermission("supplier:risk:process");if(mapper.processRisk(id,version,accepted?2:3)!=1)throw conflict();audit.save(c,accepted?"ACCEPT_RISK_RECOMMENDATION":"REJECT_RISK_RECOMMENDATION","RISK_RECOMMENDATION",id,String.valueOf(id),null,"{\"status\":"+(accepted?2:3)+"}");}
 private Metric metric(String type){return switch(type){case "WmsQualityInspectionCompleted"->new Metric("QUALITY","PASS_RATE");case "TmsShipmentDelivered"->new Metric("DELIVERY","ON_TIME_RATE");case "TmsShipmentDelayed"->new Metric("DELIVERY","DELAY_RATE");case "PurchasePriceVarianceCalculated"->new Metric("PRICE","PRICE_VARIANCE_RATE");case "PurchaseOrderConfirmed"->new Metric("RESPONSE","CONFIRM_ON_TIME_RATE");case "SupplierReturnClosed"->new Metric("QUALITY","RETURN_RATE");case "BmsReconciliationClosed"->new Metric("FINANCE","RECONCILIATION_ACCURACY");default->throw rule("不支持的绩效事实类型: "+type);};}private String write(Object v){try{return json.writeValueAsString(v);}catch(JacksonException e){throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"评分数据序列化失败");}}private static BusinessException rule(String m){return new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,m);}private static BusinessException conflict(){return new BusinessException(ErrorCode.VERSION_CONFLICT,"评分数据状态或版本已变更");}private record Metric(String dimension,String metric){}
}
